pub async fn get_scores_by_ids(pool: &sqlx::PgPool, ids: &[i32]) -> Result<Vec<GetScoresByIdsRow>, sqlx::Error> {
    sqlx::query_as!(GetScoresByIdsRow, "SELECT id, values FROM scores WHERE id = ANY($1)", ids)
        .fetch_all(pool)
        .await
}

